'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Script from 'next/script';
import type { Scene, Hotspot } from './types';

interface VirtualTourClientProps {
  scene: Scene;
  allScenes: Scene[];
}

declare global {
  interface Window {
    PhotoSphereViewer?: any;
  }
}

export default function VirtualTourClient({ scene, allScenes }: VirtualTourClientProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewerRef = useRef<any>(null);
  const markersPluginRef = useRef<any>(null);
  const router = useRouter();
  
  const [isLoading, setIsLoading] = useState(true);
  const [isDevMode, setIsDevMode] = useState(false);
  const [cameraPos, setCameraPos] = useState({ yaw: 0, pitch: 0 });
  const [lastClicked, setLastClicked] = useState({ yaw: 0, pitch: 0 });
  const [loadError, setLoadError] = useState<string | null>(null);
  const [psvReady, setPsvReady] = useState(false);
  const initAttempted = useRef(false);

  // Initialize viewer when PSV is ready
  useEffect(() => {
    if (!psvReady || !containerRef.current || initAttempted.current) {
      return;
    }

    // Prevent double initialization from React StrictMode
    initAttempted.current = true;

    console.log('Initializing viewer with scene:', scene.id);
    console.log('Container exists:', !!containerRef.current);

    try {
      const PSV = window.PhotoSphereViewer;
      if (!PSV?.Viewer) {
        throw new Error('PhotoSphereViewer.Viewer not available');
      }

      const { Viewer, MarkersPlugin } = PSV;
      console.log('Creating viewer instance...');

      // Create viewer
      const viewer = new Viewer({
        container: containerRef.current,
        panorama: scene.panorama,
        caption: scene.title,
        defaultYaw: scene.cameraPosition.yaw,
        defaultPitch: scene.cameraPosition.pitch,
        navbar: ['zoom', 'move', 'download', 'caption', 'fullscreen'],
        plugins: MarkersPlugin ? [
          [MarkersPlugin, {
            markers: scene.hotspots.map(getMarkerConfig),
          }],
        ] : [],
      });

      console.log('Viewer created:', viewer);
      viewerRef.current = viewer;

      // Setup plugins
      if (MarkersPlugin) {
        console.log('Getting MarkersPlugin...');
        const markersPlugin = viewer.getPlugin(MarkersPlugin);
        markersPluginRef.current = markersPlugin;

        if (markersPlugin) {
          markersPlugin.addEventListener('select-marker', ({ marker }: any) => {
            console.log('Marker selected:', marker);
            if (marker.data?.type === 'link') {
              router.push(`/360/${marker.data.target}`);
            }
          });
        }
      }

      // Event listeners
      viewer.addEventListener('ready', () => {
        console.log('Viewer ready event fired!');
        setIsLoading(false);
      });

      viewer.addEventListener('position-updated', () => {
        const pos = viewer.getPosition();
        setCameraPos({ yaw: pos.yaw, pitch: pos.pitch });
      });

      viewer.addEventListener('click', ({ data }: any) => {
        console.log('Viewer clicked:', data);
        if (data && markersPluginRef.current) {
          setLastClicked({ yaw: data.yaw, pitch: data.pitch });
          
          const tempId = 'temp-' + Date.now();
          markersPluginRef.current.addMarker({
            id: tempId,
            position: { yaw: data.yaw, pitch: data.pitch },
            html: `<div class="w-4 h-4 bg-red-500 rounded-full border-2 border-white animate-ping"></div>`,
            anchor: 'center center',
            size: { width: 20, height: 20 },
          });
          setTimeout(() => markersPluginRef.current?.removeMarker(tempId), 1000);
        }
      });

      viewer.addEventListener('error', (e: any) => {
        console.error('Viewer error event:', e);
        setLoadError('Failed to load panorama: ' + (e?.message || 'Unknown error'));
        setIsLoading(false);
      });

      // Fallback: if ready doesn't fire in 10 seconds, show error
      setTimeout(() => {
        if (isLoading && viewerRef.current) {
          console.log('Checking viewer state after timeout...');
          // Try to check if viewer is actually ready
          try {
            const pos = viewerRef.current.getPosition();
            console.log('Viewer position accessible:', pos);
            setIsLoading(false);
          } catch (err) {
            console.error('Viewer not accessible after timeout');
            setLoadError('Viewer initialization timeout - please refresh');
            setIsLoading(false);
          }
        }
      }, 10000);

    } catch (err) {
      console.error('Failed to initialize viewer:', err);
      setLoadError(err instanceof Error ? err.message : 'Unknown error');
      setIsLoading(false);
      initAttempted.current = false; // Allow retry
    }

    return () => {
      console.log('Cleaning up viewer...');
      if (viewerRef.current) {
        viewerRef.current.destroy();
        viewerRef.current = null;
        markersPluginRef.current = null;
        initAttempted.current = false;
      }
    };
  }, [psvReady, scene, router, isLoading]);

  // Update scene when scene prop changes
  useEffect(() => {
    if (!viewerRef.current) return;

    const viewer = viewerRef.current;
    const markersPlugin = markersPluginRef.current;

    console.log('Switching to scene:', scene.id);
    setIsLoading(true);
    
    if (markersPlugin) {
      markersPlugin.clearMarkers();
    }
    
    viewer.setPanorama(scene.panorama, {
      position: scene.cameraPosition,
      transition: 1500,
      showLoader: true,
    }).then(() => {
      console.log('Panorama switched successfully');
      if (markersPlugin) {
        scene.hotspots.forEach((hotspot) => {
          markersPlugin.addMarker(getMarkerConfig(hotspot));
        });
      }
      setIsLoading(false);
    }).catch((err: any) => {
      console.error('Failed to switch panorama:', err);
      setLoadError('Failed to load scene');
      setIsLoading(false);
    });
  }, [scene]);

  const getMarkerConfig = useCallback((hotspot: Hotspot) => {
    if (hotspot.type === 'arrow') {
      return {
        id: hotspot.id,
        position: { yaw: hotspot.position.yaw, pitch: hotspot.position.pitch },
        html: `
          <div class="hotspot-arrow flex flex-col items-center gap-1 cursor-pointer group">
            <div class="bg-blue-600/90 backdrop-blur text-white px-4 py-2 rounded-full font-bold text-sm border-2 border-white shadow-lg whitespace-nowrap group-hover:bg-blue-500 transition-colors">
              ${hotspot.label}
            </div>
            <div class="w-0 h-0 border-l-[12px] border-l-transparent border-r-[12px] border-r-transparent border-t-[16px] border-t-blue-600 drop-shadow-lg"></div>
          </div>
        `,
        anchor: 'center bottom',
        size: { width: 120, height: 60 },
        data: { target: hotspot.targetScene, type: 'link' },
        tooltip: {
          content: `<div class="bg-black/80 text-white px-3 py-1 rounded text-sm">Click to travel</div>`,
          position: 'bottom center',
          trigger: 'hover',
        },
      };
    } else {
      return {
        id: hotspot.id,
        position: { yaw: hotspot.position.yaw, pitch: hotspot.position.pitch },
        html: `
          <div class="hotspot-info w-14 h-14 bg-gradient-to-br from-amber-400 to-orange-500 rounded-full border-4 border-white flex items-center justify-center shadow-2xl cursor-pointer hover:scale-110 transition-transform">
            <svg class="w-8 h-8 text-white drop-shadow-md" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path stroke-linecap="round" stroke-linejoin="round" stroke-width="3" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path>
            </svg>
          </div>
        `,
        anchor: 'center center',
        data: { type: 'info', content: hotspot.content },
        tooltip: {
          content: `<div class="bg-amber-500 text-white px-4 py-2 rounded-lg shadow-xl max-w-xs text-sm font-medium">${hotspot.content}</div>`,
          position: 'top center',
          trigger: 'hover',
        },
      };
    }
  }, []);

  const copyToClipboard = (text: string, msg: string) => {
    navigator.clipboard.writeText(text).then(() => {
      showToast(msg);
    });
  };

  const showToast = (message: string) => {
    const toast = document.getElementById('toast');
    const toastMsg = document.getElementById('toast-msg');
    if (toast && toastMsg) {
      toastMsg.textContent = message;
      toast.classList.remove('translate-y-20', 'opacity-0');
      setTimeout(() => {
        toast.classList.add('translate-y-20', 'opacity-0');
      }, 2000);
    }
  };

  const copyCamera = () => {
    const formatted = `{ "yaw": ${cameraPos.yaw.toFixed(1)}, "pitch": ${cameraPos.pitch.toFixed(1)} }`;
    copyToClipboard(formatted, 'Camera position copied!');
  };

  const copyClicked = () => {
    const formatted = `{ "yaw": ${lastClicked.yaw.toFixed(1)}, "pitch": ${lastClicked.pitch.toFixed(1)} }`;
    copyToClipboard(formatted, 'Hotspot position copied!');
  };

  const handleScriptLoad = () => {
    console.log('PSV script loaded, window.PhotoSphereViewer:', window.PhotoSphereViewer);
    if (window.PhotoSphereViewer) {
      setPsvReady(true);
    }
  };

  const handleScriptError = (e: any) => {
    console.error('Script failed to load:', e);
    setLoadError('Failed to load 360° viewer scripts');
    setIsLoading(false);
  };

  return (
    <>
      {/* Import Map for ES Modules */}
      <Script
        id="importmap"
        type="importmap"
        dangerouslySetInnerHTML={{
          __html: JSON.stringify({
            imports: {
              "three": "https://cdn.jsdelivr.net/npm/three/build/three.module.js",
              "@photo-sphere-viewer/core": "https://cdn.jsdelivr.net/npm/@photo-sphere-viewer/core@5/index.module.js",
              "@photo-sphere-viewer/markers-plugin": "https://cdn.jsdelivr.net/npm/@photo-sphere-viewer/markers-plugin@5/index.module.js"
            }
          })
        }}
        strategy="beforeInteractive"
      />

      {/* Load Photo Sphere Viewer */}
      <Script
        type="module"
        strategy="afterInteractive"
        onLoad={handleScriptLoad}
        onError={handleScriptError}
        dangerouslySetInnerHTML={{
          __html: `
            import { Viewer } from '@photo-sphere-viewer/core';
            import { MarkersPlugin } from '@photo-sphere-viewer/markers-plugin';
            
            window.PhotoSphereViewer = { 
              Viewer,
              MarkersPlugin
            };
            
            console.log('Photo Sphere Viewer module loaded');
          `
        }}
      />

      {/* CSS */}
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@photo-sphere-viewer/core@5/index.min.css" />
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@photo-sphere-viewer/markers-plugin@5/index.min.css" />

      {/* Main HUD */}
      <div className="absolute top-0 left-0 w-full z-10 pointer-events-none p-6 flex flex-col justify-between h-full">
        <div className="flex justify-between items-start">
          <div className="bg-black/60 backdrop-blur-md border border-white/20 p-4 rounded-xl shadow-2xl pointer-events-auto">
            <h1 className="text-2xl font-bold tracking-tight text-white drop-shadow-md">
              {scene.title}
            </h1>
            <p className="text-sm text-gray-300 mt-1 max-w-md">
              {scene.description}
            </p>
          </div>

          <button
            onClick={() => setIsDevMode(!isDevMode)}
            className="bg-black/60 backdrop-blur-md border border-white/20 px-4 py-2 rounded-full text-xs font-mono text-yellow-400 flex items-center gap-2 pointer-events-auto cursor-pointer hover:bg-black/80 transition-colors"
          >
            <span className={`w-2 h-2 rounded-full animate-pulse ${isDevMode ? 'bg-green-500' : 'bg-yellow-500'}`}></span>
            DEV MODE: {isDevMode ? 'ON' : 'OFF'}
          </button>
        </div>

        <div className="flex justify-center pb-8">
          <div className="bg-black/80 backdrop-blur-md px-6 py-3 rounded-full border border-white/20 flex items-center gap-3 pointer-events-auto">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 15l-2 5L9 9l11 4-5 2zm0 0l5 5M7.188 2.239l.777 2.897M5.136 7.965l-2.898-.777M13.95 4.05l-2.122 2.122m-5.657 5.656l-2.12 2.122" />
            </svg>
            <span className="text-sm font-medium text-gray-200">Look for glowing markers • Click arrows to travel</span>
          </div>
        </div>
      </div>

      {/* Dev Tools HUD */}
      {isDevMode && (
        <div className="absolute top-24 right-6 w-80 z-20 bg-black/90 backdrop-blur-xl border border-yellow-500/30 rounded-xl shadow-2xl overflow-hidden">
          <div className="bg-yellow-500/10 border-b border-yellow-500/20 px-4 py-3 flex justify-between items-center">
            <h3 className="text-yellow-400 font-bold text-sm flex items-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
              </svg>
              Developer Tools
            </h3>
            <button onClick={() => setIsDevMode(false)} className="text-gray-400 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          <div className="p-4 space-y-4 font-mono text-sm">
            <div className="space-y-2">
              <div className="flex justify-between items-center text-gray-400 text-xs uppercase tracking-wider">
                <span>Camera Position</span>
                <span className="text-yellow-500">Live</span>
              </div>
              <div className="bg-gray-800/50 rounded-lg p-3 border border-gray-700">
                <code className="text-green-400 block mb-2">
                  {`{ "yaw": ${cameraPos.yaw.toFixed(1)}, "pitch": ${cameraPos.pitch.toFixed(1)} }`}
                </code>
                <button
                  onClick={copyCamera}
                  className="w-full bg-gray-700 hover:bg-gray-600 text-gray-300 py-1.5 px-3 rounded text-xs flex items-center justify-center gap-2 transition-colors active:scale-95"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                  </svg>
                  Copy Camera
                </button>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between items-center text-gray-400 text-xs uppercase tracking-wider">
                <span>Clicked Position</span>
                <span className="text-blue-500">Last Click</span>
              </div>
              <div className="bg-gray-800/50 rounded-lg p-3 border border-gray-700">
                <code className="text-blue-400 block mb-2">
                  {`{ "yaw": ${lastClicked.yaw.toFixed(1)}, "pitch": ${lastClicked.pitch.toFixed(1)} }`}
                </code>
                <button
                  onClick={copyClicked}
                  className="w-full bg-gray-700 hover:bg-gray-600 text-gray-300 py-1.5 px-3 rounded text-xs flex items-center justify-center gap-2 transition-colors active:scale-95"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                  </svg>
                  Copy Hotspot
                </button>
              </div>
              <p className="text-xs text-gray-500 italic">Click anywhere on the sphere to capture position</p>
            </div>

            <div className="border-t border-gray-700 pt-3 mt-3">
              <p className="text-xs text-gray-400 leading-relaxed">
                <span className="text-yellow-400 font-semibold">Tip:</span> Drag to position camera, then copy. Click on empty space to set hotspot position.
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      <div
        id="toast"
        className="fixed bottom-6 right-6 bg-green-500 text-white px-4 py-2 rounded-lg shadow-xl transform translate-y-20 opacity-0 transition-all duration-300 z-50 flex items-center gap-2"
      >
        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
        </svg>
        <span id="toast-msg">Copied to clipboard!</span>
      </div>

      {/* Loading Screen */}
      {isLoading && (
        <div className="absolute inset-0 z-50 bg-gray-900 flex flex-col items-center justify-center transition-opacity duration-700">
          <div className="border-4 border-white/10 border-l-blue-500 rounded-full w-10 h-10 animate-spin mb-4"></div>
          <div className="text-blue-400 font-mono text-sm tracking-widest">LOADING ASSETS</div>
          {loadError && (
            <div className="mt-4 text-red-400 text-sm max-w-md text-center px-4">
              Error: {loadError}
              <br />
              <button 
                onClick={() => window.location.reload()} 
                className="mt-2 underline hover:text-red-300"
              >
                Retry
              </button>
            </div>
          )}
        </div>
      )}

      {/* Viewer Container */}
      <div ref={containerRef} className="w-screen h-screen bg-gray-900" />
    </>
  );
}